def clone_graph(adj):
    n = len(adj)
    if n == 0:
        return []

    class Node:
        __slots__ = ("id", "neighbors")

        def __init__(self, i):
            self.id = i
            self.neighbors = []

    nodes = [Node(i) for i in range(n)]
    for i in range(n):
        nodes[i].neighbors = [nodes[j] for j in adj[i]]

    clones = {}

    def dfs(node):
        if node.id in clones:
            return clones[node.id]
        copy = Node(node.id)
        clones[node.id] = copy
        copy.neighbors = [dfs(nb) for nb in node.neighbors]
        return copy

    for i in range(n):
        if i not in clones:
            dfs(nodes[i])

    return [[nb.id for nb in clones[i].neighbors] for i in range(n)]
